from math import isclose

def fibonacci(n):
    """Compute the nth Fibonacci number."""
    if n <= 0:
        raise ValueError("Input must be a non-negative integer.")
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        return fibonacci(n - 1) + fibonacci(n - 2)
